async (params, browser) => {
  // Open Pinterest ideas page
  await browser.open('https://www.pinterest.com/ideas/')

  // Wait for ideas page to load
  await browser.waitForSelector('a[href*=\'/ideas/\'], [data-test-id=\'pin\'], h2, h3', 15000)

  // Let ideas content render
  await browser.wait(3000)

  // Extract trending ideas and topics
  const ideas_data = await browser.evaluate(`const topics = []; const topicEls = document.querySelectorAll('a[href*="/ideas/"]'); const seen = new Set(); for (let i = 0; i < topicEls.length; i++) { const el = topicEls[i]; const href = el.getAttribute('href') || ''; const text = el.textContent.trim(); if (text && !seen.has(text) && href.includes('/ideas/')) { seen.add(text); const imgEl = el.querySelector('img'); topics.push({ topic: text.slice(0, 200), url: 'https://www.pinterest.com' + href, image_url: imgEl ? (imgEl.getAttribute('src') || '') : '' }); } if (topics.length >= 30) break; } const featuredPins = []; const pinEls = document.querySelectorAll('[data-test-id="pin"], [data-test-id="pinWrapper"], div[data-grid-item]'); for (let i = 0; i < Math.min(pinEls.length, 15); i++) { const pin = pinEls[i]; const imgEl = pin.querySelector('img'); const linkEl = pin.querySelector('a[href*="/pin/"]'); const titleEl = pin.querySelector('[data-test-id="pinTitle"], [title]') || imgEl; featuredPins.push({ title: titleEl ? (titleEl.getAttribute('title') || titleEl.getAttribute('alt') || titleEl.textContent || '').trim().slice(0, 200) : '', image_url: imgEl ? (imgEl.getAttribute('src') || '') : '', pin_url: linkEl ? 'https://www.pinterest.com' + linkEl.getAttribute('href') : '' }); } return { source: 'Pinterest Ideas / Trending', topic_count: topics.length, topics: topics, featured_pin_count: featuredPins.length, featured_pins: featuredPins }`)

  return ideas_data
}
